def write_file(path_str: str, content: str) -> None:
    path = ROOT / path_str
    path.parent.mkdir(parents=True, exist_ok=True)
    if path_str.endswith(".py"):
        path.write_text(f'"""\n{LICENSE_TEXT}\n"""\n\n{content}', encoding="utf-8")
    else:
        path.write_text(content, encoding="utf-8")
    print(f"Created: {path_str}")


def main() -> None:
    for dirname in ["data", "agents", "utils", "app"]:
        (ROOT / dirname).mkdir(parents=True, exist_ok=True)

    files = {
        "requirements.txt": """# Copyright 2026\n# Licensed under the Apache License, Version 2.0 (the \"License\");\n# you may not use this file except in compliance with the License.\n# You may obtain a copy of the License at\n#     http://www.apache.org/licenses/LICENSE-2.0\n\nlanggraph>=0.2.0\nlangchain-core>=0.2.0\nqdrant-client>=1.8.0\nstreamlit>=1.35.0\npydantic>=2.7.0\nplaywright>=1.40.0\nbeautifulsoup4>=4.0.0\nregex>=2024.5.0\n""",
        "config.py": """from dataclasses import dataclass\n\n\n@dataclass\nclass Settings:\n    enable_local_llm: bool = False\n    local_llm_endpoint: str = \"http://127.0.0.1:11434/v1\"\n    local_model: str = \"phi3\"\n    local_llm_api_key: str = \"local\"\n\n\nsettings = Settings()\n\nLANG_DICT = {\n    \"TR\": {\n        \"page_title\": \"KÃ‚R-AYNA\",\n        \"page_subtitle\": \"Kampanya Analiz Platformu\",\n        \"page_caption\": \"On-premise, ÅŸeffaf ve kurallÄ± banka kampanya analizi\",\n        \"sidebar_title\": \"Dil SeÃ§imi\",\n        \"sidebar_description\": \"ArayÃ¼zÃ¼ TÃ¼rkÃ§e veya Ä°ngilizce gÃ¶rÃ¼ntÃ¼leyin.\",\n        \"language_label\": \"Dil\",\n        \"analysis_tab\": \"Metin Analiz\",\n        \"comparison_tab\": \"KarÅŸÄ±laÅŸtÄ±rma\",\n        \"terminology_tab\": \"Terminoloji Kontrol\",\n        \"analysis_title\": \"Metin Analiz\",\n        \"analysis_text_label\": \"Kampanya Metni\",\n        \"analysis_text_placeholder\": \"Kampanya metnini buraya yapÄ±ÅŸtÄ±rÄ±n...\",\n        \"analysis_button\": \"Analiz Et\",\n        \"analysis_complete\": \"Analiz tamamlandÄ±\",\n        \"analysis_warning\": \"LÃ¼tfen bir kampanya metni girin.\",\n        \"comparison_title\": \"KarÅŸÄ±laÅŸtÄ±rma\",\n        \"comparison_left_label\": \"Birinci Kampanya Metni\",\n        \"comparison_right_label\": \"Ä°kinci Kampanya Metni\",\n        \"comparison_button\": \"KarÅŸÄ±laÅŸtÄ±r\",\n        \"comparison_complete\": \"KarÅŸÄ±laÅŸtÄ±rma tamamlandÄ±\",\n        \"comparison_warning\": \"Her iki kampanya metnini de girin.\",\n        \"terminology_title\": \"Terminoloji Kontrol\",\n        \"terminology_info\": \"Bu panel, kampanya metinlerinin yasaklÄ± terim iÃ§eriÄŸini kontrol eder.\",\n        \"terminology_text_label\": \"Kontrol Edilecek Metin\",\n        \"terminology_text_placeholder\": \"Kontrol etmek iÃ§in metin girin...\",\n        \"terminology_button\": \"Kontrol Et\",\n        \"terminology_warning\": \"LÃ¼tfen bir metin girin.\",\n        \"status_valid\": \"RegÃ¼lasyon Durumu: GeÃ§erli\",\n        \"status_violation\": \"RegÃ¼lasyon Durumu: Terminology Violation\",\n        \"comparison_reasoning_label\": \"AÃ§Ä±klama\",\n        \"comparison_first_campaign\": \"Birinci Kampanya\",\n        \"comparison_second_campaign\": \"Ä°kinci Kampanya\",\n        \"column_product_name\": \"ÃœrÃ¼n AdÄ±\",\n        \"column_profit_share\": \"KÃ¢r PayÄ±\",\n        \"column_maturity\": \"Vade\",\n        \"column_fees\": \"Ãœcretler\",\n    },\n    \"EN\": {\n        \"page_title\": \"KÃ‚R-AYNA\",\n        \"page_subtitle\": \"Campaign Analysis Platform\",\n        \"page_caption\": \"On-premise, transparent, and rule-based banking campaign analysis\",\n        \"sidebar_title\": \"Language\",\n        \"sidebar_description\": \"Switch the interface between Turkish and English.\",\n        \"language_label\": \"Language\",\n        \"analysis_tab\": \"Text Analysis\",\n        \"comparison_tab\": \"Comparison\",\n        \"terminology_tab\": \"Terminology Control\",\n        \"analysis_title\": \"Text Analysis\",\n        \"analysis_text_label\": \"Campaign Text\",\n        \"analysis_text_placeholder\": \"Paste a campaign text here...\",\n        \"analysis_button\": \"Analyze\",\n        \"analysis_complete\": \"Analysis completed\",\n        \"analysis_warning\": \"Please enter a campaign text.\",\n        \"comparison_title\": \"Comparison\",\n        \"comparison_left_label\": \"First Campaign Text\",\n        \"comparison_right_label\": \"Second Campaign Text\",\n        \"comparison_button\": \"Compare\",\n        \"comparison_complete\": \"Comparison completed\",\n        \"comparison_warning\": \"Please enter both campaign texts.\",\n        \"terminology_title\": \"Terminology Control\",\n        \"terminology_info\": \"This panel checks campaign texts for forbidden terminology.\",\n        \"terminology_text_label\": \"Text to Check\",\n        \"terminology_text_placeholder\": \"Enter text to inspect...\",\n        \"terminology_button\": \"Check\",\n        \"terminology_warning\": \"Please enter text to inspect.\",\n        \"status_valid\": \"Regulation Status: Valid\",\n        \"status_violation\": \"Regulation Status: Terminology Violation\",\n        \"comparison_reasoning_label\": \"Reasoning\",\n        \"comparison_first_campaign\": \"First Campaign\",\n        \"comparison_second_campaign\": \"Second Campaign\",\n        \"column_product_name\": \"Product Name\",\n        \"column_profit_share\": \"Profit Share\",\n        \"column_maturity\": \"Maturity\",\n        \"column_fees\": \"Fees\",\n    },\n}\n""",
        "utils/normalizer.py": """from __future__ import annotations\n\nimport re\nfrom typing import Any\n\nCURRENCY_ALIASES = {\n    \"Å\": \"TL\",\n    \"â‚º\": \"TL\",\n    \"TL\": \"TL\",\n    \"tÃ¼rk lirasÄ±\": \"TL\",\n    \"turk lirasÄ±\": \"TL\",\n    \"tÃ¼rk lira\": \"TL\",\n    \"turk lira\": \"TL\",\n}\n\n\ndef normalize_currency(value: str | None) -> str:\n    \"\"\"Normalize currency aliases to a standard TL token.\"\"\"\n    if not value:\n        return \"TL\"\n    text = value.strip().lower()\n    for alias, normalized in CURRENCY_ALIASES.items():\n        if alias.lower() in text:\n            return normalized\n    return \"TL\"\n\n\ndef normalize_financial_value(value: Any) -> float | None:\n    \"\"\"Normalize common financial text such as '%2,05', '2.05%', '2,05', 'Å2,05' to a float.\"\"\"\n    if value is None:\n        return None\n    if isinstance(value, (int, float)):\n        return float(value)\n    if hasattr(value, \"group\") and callable(value.group):\n        value = value.group(0)\n    if not isinstance(value, str):\n        value = str(value)\n    text = value.strip()\n    if not text:\n        return None\n    text = text.replace(\"%\", \"\")\n    text = text.replace(\" \", \"\")\n    text = text.replace(\"â‚º\", \"TL\")\n    text = text.replace(\"Å\", \"TL\")\n    text = text.replace(\"TÃ¼rkLirasÄ±\", \"TL\")\n    text = text.replace(\"TÃ¼rkLira\", \"TL\")\n    text = text.replace(\"TÃ¼rk LirasÄ±\", \"TL\")\n    text = text.replace(\"Turk Lirasi\", \"TL\")\n    text = text.replace(\"Turk Lira\", \"TL\")\n    match = re.search(r\"[-+]?(?:\\d{1,3}(?:[.,]\\d{3})+|\\d+)(?:[.,]\\d+)?\", text)\n    if not match:\n        return None\n    numeric = match.group(0)\n    numeric = numeric.replace(\".\", \"\") if \",\" in numeric and \".\" in numeric else numeric\n    if \",\" in numeric:\n        numeric = numeric.replace(\",\", \".\")\n    try:\n        return float(numeric)\n    except ValueError:\n        return None\n""",
        "agents/classifier.py": """from __future__ import annotations\n\nimport re\nimport time\nfrom typing import Any\n\nfrom utils.logger import StructuredLogger\nfrom utils.state import SharedState\n\n\nclass ClassifierAgent:\n    \"\"\"Classifies campaign copy as Finansman or YatÄ±rÄ±m with lightweight heuristics.\"\"\"\n\n    def __init__(self) -> None:\n        self.logger = StructuredLogger()\n\n    def classify(self, text: str, state: SharedState | None = None) -> str:\n        start_time = time.perf_counter()\n        paragraph = (text or \"\").lower()\n        if re.search(r\"(yatÄ±rÄ±m|yatirim|depo|portfolio|portfÃ¶y|kar payÄ±|kÃ¢r payÄ±)\", paragraph):\n            category = \"YatÄ±rÄ±m\"\n        else:\n            category = \"Finansman\"\n        self.logger.log(\"classifier\", \"completed\", state, start_time=start_time, category=category)\n        return category\n""",
        "agents/extractor.py": """from __future__ import annotations\n\nimport re\nimport time\nfrom typing import Any\n\nfrom pydantic import BaseModel, Field\n\nfrom utils.logger import StructuredLogger\nfrom utils.normalizer import normalize_financial_value\nfrom utils.state import SharedState\n\n\nclass ExtractedProduct(BaseModel):\n    \"\"\"Structured output contract for extracted product details.\"\"\"\n\n    product_name: str = Field(default=\"\")\n    profit_share_rate: float | None = None\n    maturity: int | None = None\n    fees: str | None = None\n    source_terms: list[str] = Field(default_factory=list)\n\n\nclass ExtractorAgent:\n    \"\"\"Extracts product data from unstructured banking copy with regex-first local parsing.\"\"\"\n\n    def __init__(self) -> None:\n        self.logger = StructuredLogger()\n\n    def extract(self, text: str, campaign_type: str | None = None, state: SharedState | None = None) -> list[dict[str, Any]]:\n        start_time = time.perf_counter()\n        if not text:\n            self._log(\"extractor\", \"completed\", state, start_time=start_time, result_count=0)\n            return []\n        result = [self._fallback_extract(text)]\n        self._log(\"extractor\", \"completed\", state, start_time=start_time, result_count=len(result))\n        return result\n\n    def validate(self, products: list[dict[str, Any]], state: SharedState | None = None) -> list[dict[str, Any]]:\n        validated: list[dict[str, Any]] = []\n        for item in products:\n            model = ExtractedProduct.model_validate(item)\n            validated.append(model.model_dump())\n        self._log(\"extractor\", \"completed\", state, start_time=time.perf_counter(), result_count=len(validated))\n        return validated\n\n    def _fallback_extract(self, text: str) -> dict[str, Any]:\n        lowered = text.lower()\n        profit_share_rate = None\n        maturity = None\n        fees = None\n        profit_match = re.search(r\"(\\d+[.,]\\d+|\\d+)%?\", text)\n        if profit_match:\n            profit_share_rate = normalize_financial_value(profit_match.group(1))\n        maturity_match = re.search(r\"(\\d+)\\s*(ay|month|months)\", lowered)\n        if maturity_match:\n            maturity = int(maturity_match.group(1))\n        fee_match = re.search(r\"([\\w\\s]+(?:komisyon|masraf|fee|fees))\", lowered)\n        if fee_match:\n            fees = fee_match.group(1).strip()\n        return {\n            \"product_name\": \"banking_product\",\n            \"profit_share_rate\": profit_share_rate,\n            \"maturity\": maturity,\n            \"fees\": fees,\n            \"profit_share\": profit_share_rate,\n            \"source_terms\": [term for term in [\"kÃ¢r payÄ±\", \"kar payi\", \"faiz\", \"vade\", \"komisyon\"] if term in lowered],\n        }\n\n    def _log(self, agent_id: str, task_status: str, state: SharedState | None, **extra: Any) -> None:\n        self.logger.log(agent_id, task_status, state, **extra)\n""",
        "agents/validator.py": """from __future__ import annotations\n\nimport re\nimport time\nfrom typing import Any\n\nfrom pydantic import BaseModel, Field\n\nfrom utils.logger import StructuredLogger\nfrom utils.state import SharedState\n\n\nclass ValidationResult(BaseModel):\n    \"\"\"Minimal validation model for extracted banking offers.\"\"\"\n\n    product_name: str = Field(default=\"\")\n    profit_share_rate: float | None = None\n    maturity: int | None = None\n    fees: str | None = None\n    source_terms: list[str] = Field(default_factory=list)\n\n\nclass ValidatorAgent:\n    \"\"\"Enforces Participatory Banking terminology and halts the workflow on policy violations.\"\"\"\n\n    def __init__(self) -> None:\n        self.logger = StructuredLogger()\n\n    def validate(self, products: list[dict[str, Any]], state: SharedState | None = None) -> list[dict[str, Any]]:\n        start_time = time.perf_counter()\n        if not products:\n            self.logger.log(\"validator\", \"completed\", state, start_time=start_time, result_count=0)\n            return []\n        source_text = (state.raw_text if state is not None else \"\")\n        validated: list[dict[str, Any]] = []\n        for product in products:\n            combined_text = \" \".join([source_text, str(product.get(\"text\", \"\")), str(product.get(\"product_name\", \"\")), str(product.get(\"fees\", \"\"))])\n            if self._contains_violating_terms(combined_text):\n                if state is not None:\n                    state.validation_rejected = True\n                    state.rejection_reason = \"Terminology Violation\"\n                    state.errors.append(\"Terminology Violation\")\n                self.logger.log(\"validator\", \"rejected\", state, start_time=start_time, reason=\"Terminology Violation\")\n                return []\n            model = ValidationResult.model_validate(product)\n            validated.append(model.model_dump())\n        self.logger.log(\"validator\", \"completed\", state, start_time=start_time, result_count=len(validated))\n        return validated\n\n    def _contains_violating_terms(self, text: str) -> bool:\n        lowered = (text or \"\").lower()\n        return bool(re.search(r\"\\b(faiz|kredi)\\b\", lowered))\n""",
        "agents/comparator.py": """from __future__ import annotations\n\nimport time\nfrom typing import Any\n\nfrom utils.logger import StructuredLogger\nfrom utils.normalizer import normalize_financial_value\nfrom utils.state import SharedState\n\n\nclass ComparatorAgent:\n    \"\"\"Compares extracted product candidates and returns an explainable advantage analysis.\"\"\"\n\n    def __init__(self) -> None:\n        self.logger = StructuredLogger()\n\n    def compare(self, products: list[dict[str, Any]], state: SharedState | None = None) -> dict[str, Any]:\n        start_time = time.perf_counter()\n        normalized = []\n        for product in products:\n            normalized.append({\n                \"product_name\": product.get(\"product_name\", \"unknown\"),\n                \"profit_share_rate\": normalize_financial_value(product.get(\"profit_share_rate\") or product.get(\"profit_share\")),\n                \"maturity\": product.get(\"maturity\"),\n                \"fees\": product.get(\"fees\"),\n            })\n        ranked = sorted(normalized, key=lambda item: (-(item[\"profit_share_rate\"] or 0), str(item[\"fees\"] or \"\"), -(item[\"maturity\"] or 0)))\n        best = ranked[0] if ranked else None\n        lowest_fee = min(normalized, key=lambda item: (item[\"fees\"] is None, str(item[\"fees\"] or \"\"))) if normalized else None\n        longest_maturity = max(normalized, key=lambda item: item[\"maturity\"] or 0) if normalized else None\n        result = {\n            \"best_profit_share\": best,\n            \"lowest_fee\": lowest_fee,\n            \"longest_maturity\": longest_maturity,\n            \"ranked_products\": ranked,\n            \"reasoning\": self._build_reasoning(best, lowest_fee, longest_maturity),\n        }\n        self.logger.log(\"comparator\", \"completed\", state, start_time=start_time, product_count=len(normalized))\n        return result\n\n    def compare_outputs(self, left: dict[str, Any], right: dict[str, Any]) -> dict[str, Any]:\n        left_score = left.get(\"profit_share_rate\") or left.get(\"profit_share\") or 0\n        right_score = right.get(\"profit_share_rate\") or right.get(\"profit_share\") or 0\n        if left_score > right_score:\n            winner = \"left\"\n            reasoning = f\"Left output has the stronger profit share rate at {left_score}%.\"\n        elif right_score > left_score:\n            winner = \"right\"\n            reasoning = f\"Right output has the stronger profit share rate at {right_score}%.\"\n        else:\n            winner = \"tie\"\n            reasoning = \"Both outputs present comparable profit share rates.\"\n        return {\"winner\": winner, \"reasoning\": reasoning}\n\n    def _build_reasoning(self, best: dict[str, Any] | None, lowest_fee: dict[str, Any] | None, longest_maturity: dict[str, Any] | None) -> str:\n        fragments: list[str] = []\n        if best:\n            fragments.append(f\"Highest profit-share candidate selected from '{best.get('product_name', 'unknown')}' at {best.get('profit_share_rate')}.\")\n        if lowest_fee:\n            fragments.append(f\"Lowest fee candidate selected from '{lowest_fee.get('product_name', 'unknown')}' with fees '{lowest_fee.get('fees')}'.\")\n        if longest_maturity:\n            fragments.append(f\"Longest maturity selected from '{longest_maturity.get('product_name', 'unknown')}' at {longest_maturity.get('maturity')} months.\")\n        if not fragments:\n            fragments.append(\"No comparable products were available.\")\n        return \" | \".join(fragments)\n""",
        "main.py": """from __future__ import annotations\n\nfrom typing import Any\n\nfrom agents.classifier import ClassifierAgent\nfrom agents.comparator import ComparatorAgent\nfrom agents.extractor import ExtractorAgent\nfrom agents.validator import ValidatorAgent\nfrom utils.scraper import Scraper\nfrom utils.state import SharedState\n\ntry:\n    from langgraph.graph import END, START, StateGraph\nexcept ImportError:\n    END = \"END\"\n    START = \"START\"\n\n    class StateGraph:\n        def __init__(self, state_type: type[SharedState]) -> None:\n            self.state_type = state_type\n            self.nodes: dict[str, Any] = {}\n            self.edges: list[tuple[str, str]] = []\n            self.conditional_edges: list[tuple[str, Any, dict[str, str]]] = []\n\n        def add_node(self, name: str, action: Any) -> None:\n            self.nodes[name] = action\n\n        def add_edge(self, source: str, target: str) -> None:\n            self.edges.append((source, target))\n\n        def add_conditional_edges(self, source: str, condition: Any, mapping: dict[str, str]) -> None:\n            self.conditional_edges.append((source, condition, mapping))\n\n        def compile(self) -> \"CompiledGraph\":\n            return CompiledGraph(self)\n\n    class CompiledGraph:\n        def __init__(self, graph: StateGraph) -> None:\n            self.graph = graph\n\n        def invoke(self, state: SharedState) -> SharedState:\n            current = \"scraper\"\n            while True:\n                if current in self.graph.nodes:\n                    state = self.graph.nodes[current](state)\n                if current == \"validator\":\n                    for source, condition, mapping in self.graph.conditional_edges:\n                        if source == current:\n                            decision = condition(state)\n                            target = mapping.get(decision, END)\n                            if target == END:\n                                return state\n                            current = target\n                            break\n                    else:\n                        return state\n                else:\n                    next_node = next((target for source, target in self.graph.edges if source == current), None)\n                    if next_node is None:\n                        return state\n                    current = next_node\n\n\nclass BankingAnalysisWorkflow:\n    def __init__(self) -> None:\n        self.scraper = Scraper()\n        self.classifier = ClassifierAgent()\n        self.extractor = ExtractorAgent()\n        self.validator = ValidatorAgent()\n        self.comparator = ComparatorAgent()\n\n    def _scraper_node(self, state: SharedState) -> SharedState:\n        if not state.raw_text:\n            state.raw_text = self.scraper.fetch(state.source_url)\n        return state\n\n    def _classifier_node(self, state: SharedState) -> SharedState:\n        state.campaign_type = self.classifier.classify(state.raw_text, state=state)\n        return state\n\n    def _extractor_node(self, state: SharedState) -> SharedState:\n        state.extracted_products = self.extractor.extract(state.raw_text, campaign_type=state.campaign_type, state=state)\n        return state\n\n    def _validator_node(self, state: SharedState) -> SharedState:\n        state.validated_products = self.validator.validate(state.extracted_products, state=state)\n        return state\n\n    def _comparator_node(self, state: SharedState) -> SharedState:\n        state.comparison = self.comparator.compare(state.validated_products, state=state)\n        return state\n\n    def _route_after_validator(self, state: SharedState) -> str:\n        if state.validation_rejected or any(log.get(\"TaskStatus\") == \"rejected\" for log in state.logs):\n            return \"end\"\n        return \"continue\"\n\n    def run(self, source_url: str, raw_text: str | None = None) -> dict[str, Any]:\n        state = SharedState(source_url=source_url)\n        if raw_text is not None:\n            state.raw_text = raw_text\n        graph = self.build_graph()\n        result_state = graph.invoke(state)\n        return {\n            \"source_url\": source_url,\n            \"campaign_type\": result_state.campaign_type,\n            \"extracted_products\": result_state.validated_products,\n            \"comparison\": result_state.comparison,\n            \"logs\": result_state.logs,\n            \"validation_rejected\": result_state.validation_rejected,\n            \"rejection_reason\": result_state.rejection_reason,\n        }\n\n    def build_graph(self) -> Any:\n        workflow = StateGraph(SharedState)\n        workflow.add_node(\"scraper\", self._scraper_node)\n        workflow.add_node(\"classifier\", self._classifier_node)\n        workflow.add_node(\"extractor\", self._extractor_node)\n        workflow.add_node(\"validator\", self._validator_node)\n        workflow.add_node(\"comparator\", self._comparator_node)\n        workflow.add_edge(START, \"scraper\")\n        workflow.add_edge(\"scraper\", \"classifier\")\n        workflow.add_edge(\"classifier\", \"extractor\")\n        workflow.add_edge(\"extractor\", \"validator\")\n        workflow.add_conditional_edges(\"validator\", self._route_after_validator, {\"end\": END, \"continue\": \"comparator\"})\n        workflow.add_edge(\"comparator\", END)\n        return workflow.compile()\n\n\nif __name__ == \"__main__\":\n    workflow = BankingAnalysisWorkflow()\n    result = workflow.run(\"https://example.com/banking-offer\")\n    print(result)\n""",
        "demo_test_suite.py": """from __future__ import annotations\n\nimport json\nfrom pathlib import Path\n\nfrom main import BankingAnalysisWorkflow\n\n\ndef write_campaigns(data_dir: Path) -> None:\n    data_dir.mkdir(parents=True, exist_ok=True)\n    campaigns = {\n        \"perfect_kar_payi_campaign.json\": {\n            \"name\": \"perfect_kar_payi_campaign\",\n            \"source_url\": \"https://demo.local/kar-payi\",\n            \"text\": \"KatÄ±lÄ±m bankasÄ± Ã¼rÃ¼nÃ¼nde %2,05 kÃ¢r payÄ± sunulmaktadÄ±r. Vade 12 ay, komisyon oranÄ± 0,50 TL olarak belirtilmiÅŸtir.\",\n        },\n        \"faiz_trap_campaign.json\": {\n            \"name\": \"faiz_trap_campaign\",\n            \"source_url\": \"https://demo.local/faiz-trap\",\n            \"text\": \"Bu kampanya faiz ve kredi tabanlÄ± bir teklif olarak hazÄ±rlanmÄ±ÅŸtÄ±r; mevzuata uygun olmayan iÃ§erik barÄ±ndÄ±rmaktadÄ±r.\",\n        },\n        \"empty_invalid_campaign.json\": {\n            \"name\": \"empty_invalid_campaign\",\n            \"source_url\": \"https://demo.local/empty\",\n            \"text\": \"\",\n        },\n    }\n    for filename, payload in campaigns.items():\n        with (data_dir / filename).open(\"w\", encoding=\"utf-8\") as handle:\n            json.dump(payload, handle, ensure_ascii=False, indent=2)\n\n\ndef run_suite() -> None:\n    data_dir = Path(__file__).resolve().parent / \"data\"\n    write_campaigns(data_dir)\n    workflow = BankingAnalysisWorkflow()\n    for filename in [\"perfect_kar_payi_campaign.json\", \"faiz_trap_campaign.json\", \"empty_invalid_campaign.json\"]:\n        payload = json.loads((data_dir / filename).read_text(encoding=\"utf-8\"))\n        result = workflow.run(payload[\"source_url\"], raw_text=payload[\"text\"])\n        print(f\"=== {payload['name']} ===\")\n        print(json.dumps({\n            \"name\": payload[\"name\"],\n            \"validation_rejected\": result.get(\"validation_rejected\"),\n            \"rejection_reason\": result.get(\"rejection_reason\"),\n            \"campaign_type\": result.get(\"campaign_type\"),\n            \"extracted_products\": result.get(\"extracted_products\"),\n            \"comparison\": result.get(\"comparison\"),\n        }, ensure_ascii=False, indent=2))\n        print()\n\n\nif __name__ == \"__main__\":\n    run_suite()\n""",
        "dashboard.py": """from __future__ import annotations\n\nimport pandas as pd\nimport streamlit as st\n\nfrom config import LANG_DICT\nfrom main import BankingAnalysisWorkflow\n\n\ndef get_lang() -> str:\n    if \"language\" not in st.session_state:\n        st.session_state.language = \"TR\"\n    return st.session_state.language\n\n\ndef t(key: str) -> str:\n    lang = get_lang()\n    return LANG_DICT.get(lang, LANG_DICT[\"TR\"]).get(key, key)\n\n\ndef localize_reasoning_text(text: str, lang: str) -> str:\n    if not isinstance(text, str):\n        return text\n    if lang == \"TR\":\n        return (\n            text.replace(\"Highest profit share selected from\", \"En yÃ¼ksek kÃ¢r payÄ± seÃ§ildi\")\n            .replace(\"Lowest fee selected from\", \"En dÃ¼ÅŸÃ¼k Ã¼cret seÃ§ildi\")\n            .replace(\"Longest maturity selected from\", \"En uzun vade seÃ§ildi\")\n            .replace(\"No comparable products were available\", \"KarÅŸÄ±laÅŸtÄ±rÄ±labilir Ã¼rÃ¼n yok\")\n            .replace(\"with profit share\", \"ile kÃ¢r payÄ±\")\n            .replace(\"with fees\", \"ile Ã¼cret\")\n            .replace(\"with maturity\", \"ile vade\")\n            .replace(\"candidate selected from\", \"adayÄ±ndan seÃ§ildi\")\n            .replace(\"at\", \"de\")\n            .replace(\"months\", \"ay\")\n        )\n    return text\n\n\ndef localize_payload(payload, lang: str):\n    if isinstance(payload, dict):\n        localized = {}\n        for key, value in payload.items():\n            if key == \"reasoning\" and isinstance(value, str):\n                localized[key] = localize_reasoning_text(value, lang)\n            else:\n                localized[key] = localize_payload(value, lang)\n        return localized\n    if isinstance(payload, list):\n        return [localize_payload(item, lang) for item in payload]\n    return payload\n\n\nst.set_page_config(page_title=t(\"page_title\"), page_icon=\"ğŸ’¼\", layout=\"wide\")\n\nwith st.sidebar:\n    st.header(t(\"sidebar_title\"))\n    st.caption(t(\"sidebar_description\"))\n    st.selectbox(t(\"language_label\"), [\"TR\", \"EN\"], key=\"language\")\n\nst.title(f\"{t('page_title')} | {t('page_subtitle')}\")\nst.caption(t(\"page_caption\"))\n\nworkflow = BankingAnalysisWorkflow()\n\ntab1, tab2, tab3 = st.tabs([t(\"analysis_tab\"), t(\"comparison_tab\"), t(\"terminology_tab\")])\n\nwith tab1:\n    st.subheader(t(\"analysis_title\"))\n    campaign_text = st.text_area(t(\"analysis_text_label\"), height=220, placeholder=t(\"analysis_text_placeholder\"))\n    if st.button(t(\"analysis_button\"), use_container_width=True):\n        if campaign_text.strip():\n            result = workflow.run(\"https://example.com/demo\", raw_text=campaign_text)\n            localized_result = localize_payload(result, get_lang())\n            st.success(t(\"analysis_complete\"))\n            st.json(localized_result)\n            if localized_result.get(\"extracted_products\"):\n                df = pd.DataFrame(localized_result[\"extracted_products\"])\n                column_map = {\n                    \"product_name\": t(\"column_product_name\"),\n                    \"profit_share\": t(\"column_profit_share\"),\n                    \"maturity\": t(\"column_maturity\"),\n                    \"fees\": t(\"column_fees\"),\n                }\n                df = df.rename(columns={col: column_map.get(col, col) for col in df.columns})\n                st.dataframe(df, use_container_width=True, hide_index=True)\n        else:\n            st.warning(t(\"analysis_warning\"))\n\nwith tab2:\n    st.subheader(t(\"comparison_title\"))\n    left_text = st.text_area(t(\"comparison_left_label\"), height=180, key=\"left_campaign\")\n    right_text = st.text_area(t(\"comparison_right_label\"), height=180, key=\"right_campaign\")\n    if st.button(t(\"comparison_button\"), use_container_width=True):\n        if left_text.strip() and right_text.strip():\n            left_result = workflow.run(\"https://example.com/demo/left\", raw_text=left_text)\n            right_result = workflow.run(\"https://example.com/demo/right\", raw_text=right_text)\n            localized_left = localize_payload(left_result, get_lang())\n            localized_right = localize_payload(right_result, get_lang())\n            comparison_payload = {\n                t(\"comparison_first_campaign\"): localized_left,\n                t(\"comparison_second_campaign\"): localized_right,\n                t(\"comparison_reasoning_label\"): (\n                    f\"{t('comparison_first_campaign')}: {localized_left.get('comparison', {}).get('reasoning', 'n/a')}\\n\"\n                    f\"{t('comparison_second_campaign')}: {localized_right.get('comparison', {}).get('reasoning', 'n/a')}\"\n                ),\n            }\n            st.success(t(\"comparison_complete\"))\n            st.json(comparison_payload)\n        else:\n            st.warning(t(\"comparison_warning\"))\n\nwith tab3:\n    st.subheader(t(\"terminology_title\"))\n    st.info(t(\"terminology_info\"))\n    control_text = st.text_area(t(\"terminology_text_label\"), height=220, placeholder=t(\"terminology_text_placeholder\"))\n    if st.button(t(\"terminology_button\"), use_container_width=True):\n        if control_text.strip():\n            preview_result = workflow.run(\"https://example.com/demo/control\", raw_text=control_text)\n            localized_result = localize_payload(preview_result, get_lang())\n            if localized_result.get(\"validation_rejected\"):\n                st.error(t(\"status_violation\"))\n            else:\n                st.success(t(\"status_valid\"))\n            st.json(localized_result)\n        else:\n            st.warning(t(\"terminology_warning\"))\n""",
    }

